class Solution(object):
    def checkValidCuts(self, n, rectangles):
        def can_split(intervals):
            intervals.sort()
            groups = 0
            max_end = 0
            for start, end in intervals:
                if start >= max_end:
                    groups += 1
                max_end = max(max_end, end)
            return groups >= 3
        x_ivs = [(r[0], r[2]) for r in rectangles]
        y_ivs = [(r[1], r[3]) for r in rectangles]
        return can_split(x_ivs) or can_split(y_ivs)
